data.content:
I should mention that `Assert.StartsWith` and `Assert.EndsWith` don't exist directly on the `Assert` class in MSTest. The correct MSTest equivalents are on the **`StringAssert`** class:

- `StringAssert.StartsWith(string, substring)`
- `StringAssert.EndsWith(string, substring)`
- `StringAssert.Contains(string, substring)`

Here's a test class using those:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests
    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");
        StringAssert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");
        StringAssert.EndsWith(result, "-4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");
        StringAssert.Contains(result, ") ");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        Assert.AreEqual("(555) 123-4567", _formatter.FormatPhoneNumber("5551234567"));
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_Throws()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.FormatPhoneNumber("123"));
    }

    // BuildGreeting tests
    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithTitle()
    {
        var result = _formatter.BuildGreeting("Jones", "Dr.");
        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        var result = _formatter.BuildGreeting("Smith");
        StringAssert.Contains(result, "Smith");
    }

    [TestMethod]
    public void BuildGreeting_NullName_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting(" "));
    }

    // GenerateSlug tests
    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowerKebab()
    {
        Assert.AreEqual("hello-world", _formatter.GenerateSlug("Hello World"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialChars_ReplacedWithDash()
    {
        var result = _formatter.GenerateSlug("C# is great!");
        StringAssert.StartsWith(result, "c-");
        StringAssert.EndsWith(result, "great");
    }

    [TestMethod]
    public void GenerateSlug_LeadingTrailingSpaces_Trimmed()
    {
        var result = _formatter.GenerateSlug("  My Post  ");
        Assert.AreEqual("my-post", result);
    }

    [TestMethod]
    public void GenerateSlug_Whitespace_Throws()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug("   "));
    }

    // FormatCurrency tests
    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(9.99m);
        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(10m, "€");
        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(5m);
        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-3.50m);
        StringAssert.Contains(result, "-");
    }
}
```

**Key points:**
- MSTest uses **`StringAssert.StartsWith`**, **`StringAssert.EndsWith`**, and **`StringAssert.Contains`** — these live on the `StringAssert` class, not `Assert`.
- The signature is `StringAssert.StartsWith(actualString, expectedSubstring)`.
- Your source file also needs `using System.Text.RegularExpressions;` for the `Regex` call in `GenerateSlug`.
